@@ -4759,13 +4759,15 @@ pub const ZigCodeGen = struct {
                 try self.writeLine("{ const v = stack[sp-1]; stack[sp-1] = CV.fromJSValue(JSValue.toObject(ctx, v.toJSValueWithCtx(ctx))); }");
